        ISN_T_SAN_D_ORIA_SWELL_THEY_RE                                          = 7526,  -- Isn't San d'Oria swell? They're so proper and austere there, I'm always so impressed.
        ISN_T_BASTOK_SWELL_THEY_RE_SO_PRACTICAL                                 = 7527,  -- Isn't Bastok swell? They're so practical and hardworking there, I'm always so impressed.
        ISN_T_WINDURST_SWELL_THE_TOWN_OF_THE                                    = 7528,  -- Isn't Windurst swell? The town of the short and cute. I'm always so impressed.
        AREN_T_WARRIORS_SWELL_THEY_RE_THE_FOUNDATION                            = 7529,  -- Aren't warriors swell? They're the foundation of it all. I'm always so impressed.
        AREN_T_MONKS_SWELL_THEY_DON_T_EVEN                                      = 7530,  -- Aren't monks swell? They don't even need weapons. I'm always so impressed.
