        AREN_T_RED_MAGES_SWELL_THEY_RE_LIKE                                     = 7533,  -- Aren't red mages swell? They're like jacks-of-all-trades. I'm always so impressed.
        AREN_T_THIEVES_SWELL_THEY_RE_SUCH_CLEVER                                = 7534,  -- Aren't thieves swell? They're such clever folk. I'm always so impressed...at least when they're not stealing from me.
        AREN_T_PALADINS_SWELL_THEY_RE_SUCH_POWERFUL                             = 7535,  -- Aren't paladins swell? They're such powerful bastions of offense. I'm always so impressed.
        AREN_T_DARK_KNIGHTS_SWELL_THEY_RE_SUCH                                  = 7536,  -- Aren't dark knights swell? They're such cool and shadowy figures. I'm always so impressed.
        AREN_T_BEASTMASTERS_SWELL_THEY_RE_SO_IN                                 = 7537,  -- Aren't beastmasters swell? They're so in touch with nature's minions. I'm always so impressed.
        AREN_T_BARDS_SWELL_THEIR_MUSIC_SOOTHES_SAVAGE                           = 7538,  -- Aren't bards swell? Their music soothes savage beasts. I'm always so impressed.
        AREN_T_RANGERS_SWELL_THEY_RE_SUCH_GOOD                                  = 7539,  -- Aren't rangers swell? They're such good shots. I'm always so impressed.
        AREN_T_SAMURAI_SWELL_THEY_RE_SO_GOOD                                    = 7540,  -- Aren't samurai swell? They're so good with weapons. I heard they can do skillchains by themselves! I'm always so impressed.
