        AREN_T_BLUE_MAGES_SWELL_MUST_BE_GREAT                                   = 7544,  -- Aren't blue mages swell? Must be great to use your opponents' abilities against them!
        AREN_T_CORSAIRS_SWELL_LIFE_MUST_BE_THRILLING                            = 7545,  -- Aren't corsairs swell? Life must be thrilling when everything rests on the roll of the dice!
        AREN_T_PUPPETMASTERS_SWELL_I_WISH_I_HAD                                 = 7546,  -- Aren't puppetmasters swell? I wish I had a little automaton to run errands for me!
        AREN_T_DANCERS_SWELL_IT_MUST_BE_NICE                                    = 7547,  -- Aren't dancers swell? It must be nice to turn your enemy into a source of healing and support magic. I'm always so impressed.
        AREN_T_SCHOLARS_SWELL_THE_WAY_THEY_UTILIZE                              = 7548,  -- Aren't scholars swell? The way they utilize both white and black magic, not to mention their other abilities, really gets you to thinking, doesn't it?
        AREN_T_GEOMANCERS_SWELL_THEY_CAN_SUPPORT_THEIR                          = 7549,  -- Aren't geomancers swell? They can support their allies, weaken their enemies, and blast people into the past with powerful elemental magic! It makes me wonder, What can't they do?
        AREN_T_RUNE_FENCERS_SWELL_THEIR_RUNES_AREN                              = 7550,  -- Aren't rune fencers swell? Their runes aren't just pretty to look at, they're also what makes them such graceful combative technicians. I swoon every time I see one in action.
        AREN_T_HUMES_SWELL_THEY_RE_BALANCED_IN                                  = 7551,  -- Aren't Humes swell? They're balanced in every way.
        AREN_T_ELVAAN_SWELL_IF_ANY_RACE_WAS                                     = 7552,  -- Aren't Elvaan swell? If any race was fit for royalty, they sure are the one!
        AREN_T_TARUTARU_SWELL_THEY_RE_SO_CUTE                                   = 7553,  -- Aren't Tarutaru swell? They're so cute and tiny! So tiny, in fact, that sometimes I miss them when they come up to the counter!
        AREN_T_MITHRA_SWELL_THOSE_POINTY_EARS_AND                               = 7554,  -- Aren't Mithra swell? Those pointy ears and long tails quicken my heart!
        AREN_T_GALKA_SWELL_THEIR_MUSCLES_REMIND_ME                              = 7555,  -- Aren't Galka swell? Their muscles remind me of me when I was young... What? Don't you believe me?
        AREN_T_GENTLEMEN_SWELL_EXCEPT_FOR_THAT_GUY                              = 7556,  -- Aren't gentlemen swell? Except for that guy who's after my daughter. I hate him!
