        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                        = 8595,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                 = 8596,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                 = 8597,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                               = 8598,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                   = 8599,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                          = 8600,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                             = 8601,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                          = 8602,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                 = 8603,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                               = 8604,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                       = 8605,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                   = 8606,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                       = 8607,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                    = 8608,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                               = 8609,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                          = 8610,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                = 8611,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                            = 8612,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                          = 8613,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                           = 8614,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY             = 8615,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                      = 8616,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                             = 8617,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                      = 8618,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                 = 8619,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                               = 8620,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                           = 8621,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                             = 8622,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                 = 8623,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                           = 8624,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                   = 8625,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                            = 8626,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                     = 8627,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                = 8628,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                           = 8629,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                               = 8630,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                      = 8631,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        I_WAS_THINKING_THIS_OUT_LOUD_WHEN_AN                                    = 8632,  -- I was thinking this out loud when an Elvaan girl passing by stopped to talk to me.
        BUT_WHAT_ABOUT_MOOGLES_THEY_VE_GOT_WINGS                                = 8633,  -- But what about moogles? They've got wings, and they can fly, but you wouldn't call 'em birds. They've got those funny antennae, too, but they're not insects, either.
        WHEN_I_RESPONDED_TO_HER_REMARK_WITH_THE                                 = 8634,  -- When I responded to her remark with the fact that both moogles and chocobos are animals, this is what she asked:
        THEN_WHAT_S_THE_DIFFERENCE_BETWEEN_ANIMALS_AND                          = 8635,  -- Then what's the difference between animals and people?
        I_ANSWERED_PEOPLE_ARE_SMARTER_THAN_ANIMALS_AND                          = 8636,  -- I answered, People are smarter than animals. And then she retorted, People sure are more sly!
        AHAHAHA_DON_T_GET_ALL_HUFFY_ON_ME                                       = 8637,  -- Ahahaha, don't get all huffy on me! I stopped to talk because what you were saying was important.
        PEOPLE_ARE_ALL_DIFFERENT_FROM_ONE_ANOTHER_THEY                          = 8638,  -- People are all different from one another. They're different from animals, and different from plants. This difference is what makes it all worth it.
        THERE_ARE_LOTS_OF_WAYS_TO_THINK_AND                                     = 8639,  -- There are lots of ways to think and feel, and things to know and to believe. But in the end, we all come from the same source.
        THAT_S_TRUE_FOR_BOTH_PEOPLE_AND_ANIMALS                                 = 8640,  -- That's true for both people and animals.
        WE_ALL_HAVE_THIS_THING_CALLED_A_SOUL                                    = 8641,  -- We all have this thing called a soul. The souls of animals are pure and simple.
        LOOK_OVER_THERE_THAT_CHOCOBO_IS_LIVING_PROOF                            = 8642,  -- Look over there. That chocobo is living proof.
        YOU_SHOULD_ASK_SOMEONE_HOW_THAT_CHOCOBO_WAS                             = 8643,  -- You should ask someone how that chocobo was born. Then you'll have your answers.
        AND_THEN_SHE_WENT_ON_HER_WAY                                            = 8644,  -- ...And then she went on her way.
        I_WENT_TO_FIND_OUT_HOW_THAT_CHOCOBO                                     = 8645,  -- I went to find out how that chocobo was born, but no one could tell me.
        SHALOTT_SAID_THE_CHOCOBO_S_MOTHER_WAS_FROM                              = 8646,  -- Shalott said the chocobo's mother was from the stables in Bastok.
        SHE_SAID_IT_WAS_A_SPECIAL_CHOCOBO_THAT                                  = 8647,  -- She said it was a special chocobo that had silver-colored feathers on its neck.
        HOW_I_WISH_I_COULD_GO_TO_BASTOK                                         = 8648,  -- How I wish I could go to Bastok to see her for myself.
        I_WONDER_IF_THAT_ELVAAN_GIRL_WILL_BE                                    = 8649,  -- I wonder if that Elvaan girl will be passing by again anytime soon...
        THAT_ELVAAN_GIRL_TOLD_ME_THAT_BOTH_PEOPLE                               = 8650,  -- That Elvaan girl told me that both people and animals have souls. She said that the souls of animals are far more pure than those of people.
        SHE_ALSO_TOLD_ME_I_WOULD_UNDERSTAND_WHAT                                = 8651,  -- She also told me I would understand what she meant if I found out how that chocobo was born.
        ACCORDING_TO_SHALOTT_THE_CHOCOBO_S_MOTHER_IS                            = 8652,  -- According to Shalott, the chocobo's mother is from the stables in Bastok. How I wish I could go there to see her for myself...
        WHAT_CAN_I_DO_FOR_YOU_IF_YOU                                            = 8653,  -- What can I do for you? If you want to ride a chocobo, one of the girls over there can help you out.
        LATELY_A_LOT_OF_ADVENTURERS_SEEM_TO_BE                                  = 8654,  -- Lately, a lot of adventurers seem to be forgetting that a chocobo is an animal, not an object.
        YOU_SHOULD_KEEP_THAT_IN_MIND_AS_YOU                                     = 8655,  -- You should keep that in mind as you're enjoying that easy ride through monster-ridden badlands. Have a safe journey.
        A_CHOCOBO_WITH_SILVER_COLORED_FEATHERS                                  = 8656,  -- A chocobo with silver-colored feathers...?
        AH_YOU_D_BE_TALKING_ABOUT_SILVER_COMET                                  = 8657,  -- Ah, you'd be talking about Silver Comet.
        SHE_USED_TO_BE_THE_MOUNT_OF_A                                           = 8658,  -- She used to be the mount of a highly ranked general in the Bastokan navy.
        THE_GENERAL_S_SON_RECEIVED_THE_CHOCOBO_AS                               = 8659,  -- The general's son received the chocobo as a coming-of-age present, which he promptly took advantage of to leave Bastok.
        FOR_THE_LONGEST_TIME_NO_ONE_SAW_HIDE                                    = 8660,  -- For the longest time, no one saw hide nor hair of man or beast--until eventually, Silver Comet came wandering back into town...alone.
        I_HEARD_LATER_ON_THAT_THE_GENERAL_S                                     = 8661,  -- I heard later on that the general's son had lost his life somewhere in the wilds.
        ONLY_SILVER_COMET_HAD_MANAGED_TO_RETURN_UNHARMED                        = 8662,  -- Only Silver Comet had managed to return unharmed.
        IN_MEMORY_OF_HIS_SON_THE_GENERAL_ASKED                                  = 8663,  -- In memory of his son, the general asked us to take the chocobo into our care...
        BUT_THEN_ONE_DAY_SILVER_COMET_WAS_GONE                                  = 8664,  -- But then one day, Silver Comet was gone. Some chocobo thief had stolen her.
        HM_YOU_SAY_A_CHICK_OF_SILVER_COMET                                      = 8665,  -- Hm? You say a chick of Silver Comet's is being kept in the Jeuno stables? You must be mistaken.
        ANYWAY_AFTER_THE_THEFT_THE_GENERAL_EXHAUSTED_EVERY                      = 8666,  -- Anyway, after the theft, the general exhausted every avenue in search of his son's chocobo.
        HE_EVENTUALLY_FOUND_AN_ADVENTURER_WHO_ALLEGEDLY_SAW                     = 8667,  -- He eventually found an adventurer who allegedly saw a chocobo drowning in the Pashhow Marshlands.
