        SO_HERE_S_THE_LONG_AND_SHORT_OF_8                                       = 12805,  -- So here's the long and short of it. Ever since his defeat at Qu'Bia, poor [Durib/Dzapiwa/Jugowa/Mugido/Voldai/Wagwei/Zayag/Zoldof] has been plagued with self-doubt at the thought that his abilities have reached their limits.
        A_PLIGHT_NOT_UNFAMILIAR_TO_AN_ADVENTURER_SUCH                           = 12806,  -- ...A plight not unfamiliar to an adventurer such as you, I'd rrreckon. So I'm counting on you to help your buddy through the same way you helped yourself.
        I_HAVE_HERE_AN_INVITATION_FROM_AN_ORGANIZATION                          = 12807,  -- I have here an invitation from an organization called the Magian Mooglehood. Have you heard of them, by any chance?
        YOU_BETTER_HAVE_BECAUSE_THEY_RE_ASKING_THAT                             = 12808,  -- You better have, because they're asking that you show up in Ru'Lude Garrrdens with something called % in hand.
        EITHER_WAY_IT_SHOULDN_T_PROVE_A_DIFFICULT                               = 12809,  -- Either way, it shouldn't prove a difficult task for one as capable as you.
        SHOW_THIS_TO_THE_MAGIAN_MOOGLE_WHEN_YOU                                 = 12810,  -- Show this to the Magian Moogle when you get there, and he'll take care of the rrrest.
        NEXT_TIME_COMES_MOPING_THROUGH_HERE_I_LL                                = 12811,  -- Next time [Feliz/Ferdinand/Gunnar/Massimo/Oldrich/Siegward/Theobald/Zenji] comes moping through here, I'll tell him to meet you in Ru'Lude posthaste.
        NEXT_TIME_COMES_MOPING_THROUGH_HERE_I_LL_2                              = 12812,  -- Next time [Amerita/Beatrice/Henrietta/Jesimae/Karyn/Nanako/Sharlene/Sieghilde] comes moping through here, I'll tell her to meet you in Ru'Lude posthaste.
