        I_CANNOT_ADEQUATELY_EXPRESS_THE_DEPTH_OF_MY                             = 13109,  -- I cannot adequately express the depth of my remorse. Had I not failed time and time again, then maybe...
        I_M_VERY_VERY_VERY_SORRY_I_FAILED                                       = 13110,  -- I'm very very very sorry I failed you, Luto! I'll make it up to you! I promise!
        MY_SINCEREST_APOLOGIES_LUTO_I_NEVER_ONCE_CONSIDERED                     = 13111,  -- My sincerest apologies, Luto. I never once considered the bind in which my failures would entrap you...
        HOW_UNBECOMING_OF_ME_I_AM_SUPPOSED_TO                                   = 13112,  -- How unbecoming of me. I am supposed to help contribute to your business, yet I cannot even do that...
