        I_FEEL_SORRIER_THAN_A_SALTED_SEA_SLUG                                   = 13115,  -- I feel sorrier than a salted sea slug, Luto! What can I do to make things better!? I'll do everything within my power to help you!
        I_ALONE_SHOULD_BEAR_THIS_BURDEN_NOT_YOU                                 = 13116,  -- I alone should bear this burden--not you, Luto. You have been so kind to me, despite my myriad missteps.
        I_M_SORRY_LUTO_I_SHOULD_NOT_HAVE                                        = 13117,  -- I'm sorry, Luto. I should not have failed you so.
        CUT_THE_HISTRRRIONICS_ARE_YOU_AN_ADVENTURER_OR                          = 13118,  -- Cut the histrrrionics! Are you an adventurer or some mewling kitten!?
