        YOUR_MENTAL_ACUITY_IS_MOST_LAUDABLE_LUTO_I                              = 13196,  -- Your mental acuity is most laudable, Luto. I expected nothing less from my employer. I shall expend my utmost effort in hopes this training will lead to more steady work.
        AWWW_ANOTHER_TRIAL_IN_TANDEM_JUST_HOW_MANY                              = 13197,  -- Awww, another trial in tandem? Just how many of these things are there!?
        A_NEW_TRAINING_MISSION_EH_WELL_I_M                                      = 13198,  -- A new training mission, eh? Well, I'm certainly not one to pass up a chance at impressing the ladies...especially after how I wowed the crowd last time.
