        OHO_I_MAY_NOT_HAVE_A_PRIME_WEAPON                                       = 14033,  -- Oho. I may not have a Prime Weapon, but I promise that my skills are more than sufficient.
        THEN_WE_HAVE_OUR_TASKS_LET_US_SEE                                       = 14034,  -- Then we have our tasks. Let us see them through.
        THIS_IS_OUR_WATERSHED_MOMENT_WE_MUST_DEFEAT                             = 14035,  -- This is our watershed moment. We must defeat Garazu-Horeizu and his minions.
        BEST_OF_LUCK_TO_US_ALL                                                  = 14036,  -- Best of luck to us all.
        IT_HAS_BEEN_A_SPELL_HASN_T_IT                                           = 14037,  -- %. It has been a spell, hasn't it?
        YOU_DID_WELL_IN_RIDDING_US_OF_GARAZU                                    = 14038,  -- You did well in ridding us of Garazu-Horeizu and Chaos.
        I_WOULD_VENTURE_TO_SAY_THAT_YOUR_PERFORMANCE                            = 14039,  -- I would venture to say that your performance exceeded my wildest expectations.
        SO_MUCH_SO_IN_FACT_THAT_I_FIND                                          = 14040,  -- So much so, in fact, that I find myself at a bit of a loss.
        THE_ORIGINAL_PLAN_INVOLVED_MY_MASTER_HAVING_A                           = 14041,  -- The original plan involved my master having a bit more of a...pivotal role in the aftermath, so to speak.
        BUT_YOU_KEPT_ALL_THE_BEST_PARTS_FOR                                     = 14042,  -- But you kept all the best parts for yourself.
        STILL_HE_WAS_QUITE_PLEASED_WITH_HOW_YOU                                 = 14043,  -- Still, he was quite pleased with how you presented yourself during the entire ordeal.
        AND_MY_EFFORTS_WERE_REWARDED_IN_TURN_AS                                 = 14044,  -- And my efforts were rewarded in turn, as I have been permitted to remain in this world for a spell.
        A_CURSE_IN_DISGUISE_IF_YOU_WILL_FOR                                     = 14045,  -- A curse in disguise, if you will, for I had hoped to return to his side.
        YET_YOU_DESERVE_TO_KNOW_A_LITTLE_BIT                                    = 14046,  -- Yet you deserve to know a little bit more...perhaps my true name. Consider it a gift.
        I_AM_MARKGRAF_ELIGOS_AND_I_SERVE_AS                                     = 14047,  -- I am Markgraf Eligos, and I serve as one of Odin's elite.
        MAY_OUR_RELATIONSHIP_REMAIN_AS_FRUITFUL_GOING_FORWARD                   = 14048,  -- May our relationship remain as fruitful going forward as it has been to date.
        YES_GOING_FORWARD_AS_I_STILL_HAVE_THE                                   = 14049,  -- Yes, going forward, as I still have the usual tasks for you to fulfill.
        THOUGH_GARAZU_HOREIZU_NO_LONGER_POSES_A_THREAT                          = 14050,  -- Though Garazu-Horeizu no longer poses a threat, his hypnosis magic has still not completely dissipated from the land.
        AND_GIVEN_THE_DETAILS_OF_OUR_PACT_THAT                                  = 14051,  -- And given the details of our pact, that means you still have your end to hold up.
